// Compare sequential vs parallel async timing

exercises.expected_solution:
import java.util.concurrent.*;
import java.util.*;
import java.util.stream.*;
public class App {
    static void sleep(long ms) {
        try { Thread.sleep(ms); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
    }
    public static void main(String[] args) throws Exception {
        // Sequential:
        long seqStart = System.currentTimeMillis();
        for (int i = 0; i < 4; i++) sleep(150);
        long seqTime = System.currentTimeMillis() - seqStart;
        System.out.printf("Sequential: ~%dms%n", (seqTime / 100) * 100);

        // Parallel async:
        long parStart = System.currentTimeMillis();
        List<CompletableFuture<Void>> futures = IntStream.range(0, 4)
            .mapToObj(i -> CompletableFuture.runAsync(() -> sleep(150)))
            .collect(Collectors.toList());
        CompletableFuture.allOf(futures.toArray(new CompletableFuture[0])).join();
        long parTime = System.currentTimeMillis() - parStart;
        System.out.printf("Parallel async: ~%dms%n", (parTime / 100) * 100);
        System.out.printf("Speedup: ~%dx%n", Math.round((double) seqTime / parTime));
    }
}

