import java.util.concurrent.*;
import com.fasterxml.jackson.databind.*;
public class App {
    static final ObjectMapper MAPPER = new ObjectMapper();
    // Simulate: returns (statusCode, body) pair
    record MockResponse(int status, String body) {}

    public static void main(String[] args) throws Exception {
        CompletableFuture.supplyAsync(() ->
            new MockResponse(200, "{\"city\":\"Bengaluru\",\"temp\":28}"))
        .thenApply(r -> {
            if (r.status() != 200) throw new RuntimeException("HTTP " + r.status());
            return r.body();
        })
        .thenApply(body -> {
            try { return MAPPER.readTree(body); }
            catch (Exception e) { throw new RuntimeException(e); }
        })
        .thenAccept(json -> {
            System.out.println("City: " + json.path("city").asText());
            System.out.println("Temp: " + json.path("temp").asInt() + "°C");
        })
        .get();
    }
}

