import java.util.concurrent.*;
import java.util.*;
import java.util.stream.*;
public class App {
    record Result(String id, int value, boolean success) {}

    static CompletableFuture<Result> fetch(String id, boolean willSucceed) {
        return CompletableFuture.supplyAsync(() -> {
            if (!willSucceed) throw new RuntimeException("Simulated failure for " + id);
            return new Result(id, id.hashCode() % 1000, true);
        }).exceptionally(ex -> new Result(id, -1, false));
    }

    public static void main(String[] args) throws Exception {
        List<CompletableFuture<Result>> futures = List.of(
            fetch("A", true), fetch("B", false), fetch("C", true),
            fetch("D", false), fetch("E", true));

        CompletableFuture.allOf(futures.toArray(new CompletableFuture[0]))
            .thenRun(() -> {
                List<Result> results = futures.stream()
                    .map(CompletableFuture::join).collect(Collectors.toList());
                long successes = results.stream().filter(Result::success).count();
                long failures  = results.size() - successes;
                System.out.println("Results collected: " + results.size());
                System.out.println("Successful: " + successes);
                System.out.println("Failed (used default): " + failures);
            }).get();
    }
}

