import java.util.concurrent.*;
import java.util.*;
import java.util.stream.*;
import com.fasterxml.jackson.databind.*;
public class App {
    static final ObjectMapper MAPPER = new ObjectMapper();
    record Quote(String symbol, double price) {}

    static CompletableFuture<Quote> fetchQuoteAsync(String symbol) {
        Map<String, Integer> prices = Map.of(
            "TCS",3890, "RELIANCE",2450, "INFY",1560, "HDFC",1679, "WIPRO",412);
        return CompletableFuture.supplyAsync(() -> {
            try { Thread.sleep(50); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
            String json = "{\"symbol\":\"" + symbol + "\",\"price\":" + prices.get(symbol) + "}";
            try {
                JsonNode node = MAPPER.readTree(json);
                return new Quote(node.path("symbol").asText(), node.path("price").asDouble());
            } catch (Exception e) { throw new RuntimeException(e); }
        });
    }

    public static void main(String[] args) throws Exception {
        long start = System.currentTimeMillis();
        List<String> symbols = List.of("TCS", "RELIANCE", "INFY", "HDFC", "WIPRO");

        List<CompletableFuture<Quote>> futures = symbols.stream()
            .map(App::fetchQuoteAsync).collect(Collectors.toList());

        CompletableFuture.allOf(futures.toArray(new CompletableFuture[0]))
            .thenRun(() -> {
                System.out.println("=== Async Stock Dashboard ===");
                System.out.printf("Fetched in ~%dms%n%n",
                    (System.currentTimeMillis() - start) / 10 * 10);
                futures.stream()
                    .map(CompletableFuture::join)
                    .sorted((a, b) -> Double.compare(b.price(), a.price()))
                    .forEach(q -> System.out.printf("%-12s ₹%,6.0f%n", q.symbol(), q.price()));
            })
            .get();
    }
}

