import java.util.concurrent.*;
import java.util.*;
import java.util.stream.*;
public class App {
    record PriceResult(String source, int price, long ms) {}

    static void sleep(long ms) {
        try { Thread.sleep(ms); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
    }

    static CompletableFuture<PriceResult> fetchPrice(String source, int price, long delay) {
        return CompletableFuture.supplyAsync(() -> {
            long start = System.currentTimeMillis();
            sleep(delay);
            long ms = System.currentTimeMillis() - start;
            System.out.printf("%-10s ₹%,d (%dms)%n", source + ":", price, ms);
            return new PriceResult(source, price, ms);
        });
    }

    public static void main(String[] args) throws Exception {
        System.out.println("Fetching from 3 price APIs in parallel...");
        long start = System.currentTimeMillis();

        List<CompletableFuture<PriceResult>> futures = List.of(
            fetchPrice("Flipkart", 45999, 180),
            fetchPrice("Amazon",   46499, 120),
            fetchPrice("Meesho",   44999, 200));

        CompletableFuture.allOf(futures.toArray(new CompletableFuture[0]))
            .thenRun(() -> {
                PriceResult best = futures.stream()
                    .map(CompletableFuture::join)
                    .min(Comparator.comparingInt(PriceResult::price))
                    .orElseThrow();
                System.out.printf("Best price: ₹%,d from %s%n", best.price(), best.source());
                System.out.printf("Fetched in ~%dms%n",
                    (System.currentTimeMillis() - start) / 100 * 100);
            })
            .get();
    }
}

