import java.util.concurrent.*;
import java.util.function.*;
// Async retry with exponential backoff

exercises.expected_solution:
import java.util.concurrent.*;
import java.util.function.*;
public class App {
    static void sleep(long ms) {
        try { Thread.sleep(ms); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
    }

    static <T> CompletableFuture<T> retryAsync(
            Supplier<CompletableFuture<T>> taskSupplier, int maxRetries) {
        return taskSupplier.get().exceptionallyCompose(ex -> {
            if (maxRetries <= 0) return CompletableFuture.failedFuture(ex);
            long backoff = (long)(100 * Math.pow(2, 3 - maxRetries));
            System.out.printf("Attempt %d failed — retrying in %dms%n",
                4 - maxRetries, backoff);
            sleep(backoff);
            return retryAsync(taskSupplier, maxRetries - 1);
        });
    }

    public static void main(String[] args) throws Exception {
        int[] count = {0};
        Supplier<CompletableFuture<String>> task = () -> CompletableFuture.supplyAsync(() -> {
            count[0]++;
            if (count[0] < 3) throw new RuntimeException("transient error");
            System.out.println("Attempt " + count[0] + " succeeded: result");
            return "result";
        });
        String result = retryAsync(task, 3).get();
        System.out.println("Final: " + result);
    }
}

