import java.util.concurrent.*;
import java.util.*;
import java.util.stream.*;
import java.nio.file.*;
import com.fasterxml.jackson.databind.*;
import com.fasterxml.jackson.databind.node.*;
import com.fasterxml.jackson.core.type.*;

public class App {
    static final ObjectMapper MAPPER = new ObjectMapper();
    record Payment(String id, String status, int amount) {}

    // Simulate API returning JSON array of payments:
    static CompletableFuture<List<Payment>> fetchPayments(String region, String jsonData) {
        return CompletableFuture.supplyAsync(() -> {
            try {
                Thread.sleep(50 + (int)(Math.random()*100));
                return MAPPER.readValue(jsonData, new TypeReference<List<Payment>>(){});
            } catch (Exception e) { throw new RuntimeException(e); }
        });
    }

    public static void main(String[] args) throws Exception {
        // Simulate 3 regional API responses:
        String north = "[{\"id\":\"P001\",\"status\":\"SUCCESS\",\"amount\":1500}," +
            "{\"id\":\"P002\",\"status\":\"FAILED\",\"amount\":800}," +
            "{\"id\":\"P003\",\"status\":\"SUCCESS\",\"amount\":2200}]";
        String south = "[{\"id\":\"P004\",\"status\":\"SUCCESS\",\"amount\":999}," +
            "{\"id\":\"P005\",\"status\":\"FAILED\",\"amount\":450}," +
            "{\"id\":\"P006\",\"status\":\"SUCCESS\",\"amount\":3500}]";
        String west  = "[{\"id\":\"P007\",\"status\":\"FAILED\",\"amount\":1200}," +
            "{\"id\":\"P008\",\"status\":\"SUCCESS\",\"amount\":750}," +
            "{\"id\":\"P009\",\"status\":\"SUCCESS\",\"amount\":2800}]";

        List<CompletableFuture<List<Payment>>> futures = List.of(
            fetchPayments("north", north),
            fetchPayments("south", south),
            fetchPayments("west",  west));

        CompletableFuture.allOf(futures.toArray(new CompletableFuture[0]))
            .thenRun(() -> {
                List<Payment> all = futures.stream()
                    .map(CompletableFuture::join)
                    .flatMap(List::stream)
                    .collect(Collectors.toList());

                long successful = all.stream().filter(p -> "SUCCESS".equals(p.status())).count();
                long failed     = all.stream().filter(p -> "FAILED" .equals(p.status())).count();
                long total      = all.stream().mapToLong(Payment::amount).sum();

                // Build JSON report:
                ObjectNode report = MAPPER.createObjectNode();
                report.put("apisQueried", futures.size());
                report.put("totalPayments", all.size());
                report.put("successful",    successful);
                report.put("failed",        failed);
                report.put("totalAmount",   total);

                try {
                    Files.writeString(Path.of("report.json"),
                        MAPPER.writerWithDefaultPrettyPrinter().writeValueAsString(report));
                } catch (Exception e) { throw new RuntimeException(e); }

                System.out.println("=== Payment Aggregation Report ===");
                System.out.println("APIs queried: " + futures.size());
                System.out.println("Total payments: " + all.size());
                System.out.println("Successful: " + successful + "  |  Failed: " + failed);
                System.out.println("Total amount: ₹" + total);
                System.out.println("Report written: report.json");
            })
            .get();
    }
}
